import { useState } from "react";
import { useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { login } from "../authReducer";
import bcrypt from "bcryptjs";

function Register() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [role, setRole] = useState("student");

  async function handleRegister(e) {
    e.preventDefault();
    // Запрещаем регистрацию с email администратора
    if (email === "admin@school.com") {
      alert("This email is reserved for the admin and cannot be registered.");
      return;
    }

    const hashedPassword = await bcrypt.hash(password, 10);
    const newUser = { email, password: hashedPassword, name, role };

    try {
      const response = await fetch("http://localhost:3001/users", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newUser),
      });

      if (response.ok) {
        const user = await response.json();
        dispatch(login(user));
        navigate("/dashboard");
      } else {
        alert("Registration failed");
      }
    } catch (error) {
      console.error("Fetch error:", error);
      alert("Failed to register due to a network error.");
    }
  }

  return (
    <form onSubmit={handleRegister}>
      <input
        type="text"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />
      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        required
      />
      <select value={role} onChange={(e) => setRole(e.target.value)}>
        <option value="student">Student</option>
        <option value="teacher">Teacher</option>
        {/* Убрана опция admin */}
      </select>
      <button type="submit">Register</button>
    </form>
  );
}

export default Register;
